import { useEffect, useState } from "react";

const SIZE = 10;

const EMPTY = 0;
const SNAKE = 1;
const FOOD = 2;

function emptyBoard() {
  return Array.from(
    { length: SIZE },
    () => Array(SIZE).fill(EMPTY)
  );
}

function randomFood(snake) {
  while (true) {
    const row = Math.floor(Math.random() * SIZE);
    const col = Math.floor(Math.random() * SIZE);

    if (!snake.some(([r, c]) => r === row && c === col)) {
      return [row, col];
    }
  }
}

export default function Snake() {
  const [snake, setSnake] = useState([
    [5, 5],
  ]);

  const [food, setFood] = useState(
    [2, 2]
  );

  const [direction, setDirection] = useState([0, 1]);

  useEffect(() => {
    function keyDown(e) {
      if (e.key === "ArrowUp") {
        setDirection([-1, 0]);
      }

      if (e.key === "ArrowDown") {
        setDirection([1, 0]);
      }

      if (e.key === "ArrowLeft") {
        setDirection([0, -1]);
      }

      if (e.key === "ArrowRight") {
        setDirection([0, 1]);
      }
    }

    window.addEventListener("keydown", keyDown);

    return () => {
      window.removeEventListener("keydown", keyDown);
    };
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      move();
    }, 300);

    return () => clearInterval(timer);
  });

  function move() {
    const [headRow, headCol] = snake[0];

    const newHead = [
      headRow + direction[0],
      headCol + direction[1],
    ];

    if (
      newHead[0] < 0 ||
      newHead[0] >= SIZE ||
      newHead[1] < 0 ||
      newHead[1] >= SIZE
    ) {
      return;
    }

    const nextSnake = [
      newHead,
      ...snake,
    ];

    if (
      newHead[0] === food[0] &&
      newHead[1] === food[1]
    ) {
      setFood(randomFood(nextSnake));
    } else {
      nextSnake.pop();
    }

    setSnake(nextSnake);
  }

  const board = emptyBoard();

  for (const [r, c] of snake) {
    board[r][c] = SNAKE;
  }

  board[food[0]][food[1]] = FOOD;

  return (
    <main>
      <h1>🐍 Snake</h1>

      <table style={{fontFamily: "monospace"}}>
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  style={{
                    width: "2rem",
                    height: "2rem",
                    border: "1px solid",
                    textAlign: "center",
                  }}
                >
                  {
                    cell === SNAKE
                      ? "🟩"
                      : cell === FOOD
                      ? "🍎"
                      : ""
                  }
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
